+        "operation": "series_expanding_quantile",
+        "oracle_source": "live_legacy_pandas",
+        "quantile_value": 0.5,
+        "left": {
+            "name": "vals",
+            "index": [
+                { "kind": "int64", "value": 0 },
+                { "kind": "int64", "value": 1 },
+                { "kind": "int64", "value": 2 },
+                { "kind": "int64", "value": 3 },
+                { "kind": "int64", "value": 4 }
